SELECT ?item ?itemLabel WHERE {
  ?item wdt:P2048 ?height.
  ?height wikibase:quantityAmount ?value;
          wikibase:quantityUnit wd:Q11573.
  FILTER(?value > 600)
  ?item rdfs:label ?itemLabel.
  FILTER(LANG(?itemLabel) = "en")
}

